    private static string AsString(object? value) => value?.ToString() ?? string.Empty;

    private static float AsFloat(object? value)
    {
        return value switch
        {
            null => 0f,
            float floatValue => floatValue,
            double doubleValue => (float)doubleValue,
            int intValue => intValue,
            long longValue => longValue,
            decimal decimalValue => (float)decimalValue,
            string stringValue when float.TryParse(stringValue, NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed) => parsed,
            _ => 0f
        };
    }

    private static bool AsBool(object? value)
    {
        return value switch
        {
            bool boolValue => boolValue,
            string stringValue when bool.TryParse(stringValue, out var parsed) => parsed,
            int intValue => intValue != 0,
            long longValue => longValue != 0,
            _ => false
        };
    }

    private bool TryGetComponentOverrideValue(string nodePath, string propertyName, out object? value)
    {
        value = null;
        if (_componentOverrides == null || !_componentOverrides.TryGetValue(nodePath, out var propertyOverrides))
        {
            return false;
        }

        if (propertyOverrides.TryGetValue(propertyName, out value))
        {
            return true;
        }

        foreach (var candidate in propertyOverrides)
        {
            if (string.Equals(candidate.Key, propertyName, StringComparison.OrdinalIgnoreCase))
            {
                value = candidate.Value;
                return true;
            }
        }

        return false;
    }

    private static StyleLength ParseStyleLength(string value)
    {
        if (string.IsNullOrWhiteSpace(value))
        {
            return StyleKeyword.Null;
        }

        if (string.Equals(value, "auto", StringComparison.OrdinalIgnoreCase))
        {
            return StyleKeyword.Auto;
        }

        if (value.EndsWith("%", StringComparison.Ordinal))
        {
            var number = value[..^1];
            return float.TryParse(number, NumberStyles.Float, CultureInfo.InvariantCulture, out var percent)
                ? new StyleLength(new Length(percent, LengthUnit.Percent))
                : StyleKeyword.Null;
        }

        if (value.EndsWith("px", StringComparison.OrdinalIgnoreCase))
        {
            var number = value[..^2];
            return float.TryParse(number, NumberStyles.Float, CultureInfo.InvariantCulture, out var pixels)
                ? new StyleLength(pixels)
                : StyleKeyword.Null;
        }

        return float.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out var raw)
            ? new StyleLength(raw)
            : StyleKeyword.Null;
    }

    private static float ParseStyleFloat(string value)
    {
        if (string.IsNullOrWhiteSpace(value))
        {
            return 0f;
        }

        var normalized = value.EndsWith("px", StringComparison.OrdinalIgnoreCase)
            ? value[..^2]
            : value;

        return float.TryParse(normalized, NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed)
            ? parsed
            : 0f;
    }

    private static Position ParsePosition(string value)
        => string.Equals(value, "absolute", StringComparison.OrdinalIgnoreCase)
            ? Position.Absolute
            : Position.Relative;

    private static FlexDirection ParseFlexDirection(string value)
        => string.Equals(value, "row", StringComparison.OrdinalIgnoreCase)
            ? FlexDirection.Row
            : FlexDirection.Column;

    private static Overflow ParseOverflow(string value)
        => string.Equals(value, "hidden", StringComparison.OrdinalIgnoreCase)
            ? Overflow.Hidden
            : Overflow.Visible;

    private static Align ParseAlign(string value)
        => value.ToLowerInvariant() switch
        {
            "flex-start" => Align.FlexStart,
            "center" => Align.Center,
            "flex-end" => Align.FlexEnd,
            "stretch" => Align.Stretch,
            "auto" => Align.Auto,
            _ => Align.Stretch
        };

    private static Justify ParseJustify(string value)
        => value.ToLowerInvariant() switch
        {
            "flex-start" => Justify.FlexStart,
            "center" => Justify.Center,
            "flex-end" => Justify.FlexEnd,
            "space-between" => Justify.SpaceBetween,
            "space-around" => Justify.SpaceAround,
            "space-evenly" => Justify.SpaceEvenly,
            _ => Justify.FlexStart
        };

    private static string? ResolveMappedStyleValue(object? value, string? fallbackValue, params string[] mappings)
    {
        var key = AsString(value);

        for (var index = 0; index + 1 < mappings.Length; index += 2)
        {
            if (string.Equals(mappings[index], key, StringComparison.OrdinalIgnoreCase))
            {
                return mappings[index + 1];
            }
        }

        return string.IsNullOrWhiteSpace(key) ? fallbackValue : key;
    }

    private static Color ParseStyleColor(string? value, string? fallbackValue)
    {
        if (!string.IsNullOrWhiteSpace(value) && ColorUtility.TryParseHtmlString(value, out var parsed))
        {
            return parsed;
        }

        if (!string.IsNullOrWhiteSpace(fallbackValue) && ColorUtility.TryParseHtmlString(fallbackValue, out var fallback))
        {
            return fallback;
        }

        return default;
    }

    private static void SetImageSource(Image image, string resourcePath)
    {
        if (string.IsNullOrWhiteSpace(resourcePath))
        {
            image.image = null;
            return;
        }

        var normalized = resourcePath.Replace("\\", "/", StringComparison.Ordinal).TrimStart('/');
        var extensionIndex = normalized.LastIndexOf('.');
        if (extensionIndex > 0)
        {
            normalized = normalized[..extensionIndex];
        }

        image.image = Resources.Load<Texture2D>(normalized);
    }

    private static void ApplyTextLabelStyle(Label label, bool wrapText)
    {
        label.style.whiteSpace = wrapText ? WhiteSpace.Normal : WhiteSpace.NoWrap;
        label.style.flexShrink = wrapText ? 1 : 0;
        label.style.overflow = wrapText ? Overflow.Hidden : Overflow.Visible;
    }

    private static bool ApplyFontFamily(VisualElement element, string? familyName, float pointSize)
    {
        if (element == null || string.IsNullOrWhiteSpace(familyName))
        {
            return false;
        }

        if (!TryResolveFontDefinition(familyName, pointSize, out var fontDefinition))
        {
            return false;
        }

        element.style.unityFontDefinition = fontDefinition;
        return true;
    }

    private static bool TryResolveFontDefinition(string? familyName, float pointSize, out FontDefinition fontDefinition)
    {
        fontDefinition = default;

        if (string.IsNullOrWhiteSpace(familyName))
        {
            return false;
        }

        var normalizedFamily = familyName.Trim();
        var normalizedSize = Mathf.Max(1, Mathf.RoundToInt(pointSize));
        var cacheKey = $"{normalizedFamily}|{normalizedSize}";

        if (s_fontDefinitions.TryGetValue(cacheKey, out fontDefinition))
        {
            return true;
        }

        if (TryLoadSdfFontAsset(normalizedFamily, out var fontAsset))
        {
            fontDefinition = FontDefinition.FromSDFFont(fontAsset);
            s_fontDefinitions[cacheKey] = fontDefinition;
            return true;
        }

        if (!TryLoadFont(normalizedFamily, normalizedSize, out var font))
        {
            return false;
        }

        fontDefinition = FontDefinition.FromFont(font);
        s_fontDefinitions[cacheKey] = fontDefinition;
        return true;
    }

    private static bool TryLoadSdfFontAsset(string familyName, out FontAsset fontAsset)
    {
        fontAsset = null!;

        var normalizedFamily = familyName.Trim();
        if (s_sdfFontAssets.TryGetValue(normalizedFamily, out fontAsset))
        {
            return fontAsset != null;
        }

        fontAsset = LoadBundledSdfFontAsset(normalizedFamily)!;
        if (fontAsset == null)
        {
            return false;
        }

        s_sdfFontAssets[normalizedFamily] = fontAsset;
        return true;
    }

    private static FontAsset? LoadBundledSdfFontAsset(string familyName)
    {
        var normalizedFamily = familyName.Trim();

        if (s_fontResourcePaths.TryGetValue(normalizedFamily, out var resourcePath))
        {
            return Resources.Load<FontAsset>(resourcePath);
        }

        var compactName = normalizedFamily.Replace(" ", string.Empty, StringComparison.Ordinal).Replace("-", string.Empty, StringComparison.Ordinal);
        return Resources.Load<FontAsset>($"BoomHudFonts/{compactName}") ?? Resources.Load<FontAsset>($"BoomHudFonts/{normalizedFamily}");
    }

    private static bool TryLoadFont(string familyName, int pointSize, out Font font)
    {
        font = null!;

        var resourceFont = LoadBundledFont(familyName);
        if (resourceFont != null)
        {
            font = resourceFont;
            return true;
        }

        var fontCandidates = ExpandFontFamilyCandidates(familyName);
        foreach (var candidate in fontCandidates)
        {
            resourceFont = LoadBundledFont(candidate);
            if (resourceFont != null)
            {
                font = resourceFont;
                return true;
            }
        }

        try
        {
            var osFont = Font.CreateDynamicFontFromOSFont(fontCandidates, pointSize);
            if (osFont == null)
            {
                return false;
            }

            font = osFont;
            return true;
        }
        catch
        {
            return false;
        }
    }

    private static Font? LoadBundledFont(string familyName)
    {
        var normalizedFamily = familyName.Trim();

        if (s_fontResourcePaths.TryGetValue(normalizedFamily, out var resourcePath))
        {
            return Resources.Load<Font>(resourcePath);
        }

        var compactName = normalizedFamily.Replace(" ", string.Empty, StringComparison.Ordinal).Replace("-", string.Empty, StringComparison.Ordinal);
        return Resources.Load<Font>($"BoomHudFonts/{compactName}") ?? Resources.Load<Font>($"BoomHudFonts/{normalizedFamily}");
    }

    private static string[] ExpandFontFamilyCandidates(string familyName)
    {
        var rawCandidates = familyName.Split(',');
        var expanded = new List<string>();

        foreach (var rawCandidate in rawCandidates)
        {
            var candidate = rawCandidate.Trim().Trim('\'', '"');
            if (string.IsNullOrWhiteSpace(candidate))
            {
                continue;
            }

            switch (candidate.ToLowerInvariant())
            {
                case "monospace":
                    expanded.Add("Consolas");
                    expanded.Add("Cascadia Mono");
                    expanded.Add("Courier New");
                    expanded.Add("Lucida Console");
                    break;
                case "sans-serif":
                case "sans serif":
                    expanded.Add("Segoe UI");
                    expanded.Add("Arial");
                    break;
                case "serif":
                    expanded.Add("Georgia");
                    expanded.Add("Times New Roman");
                    break;
                default:
                    expanded.Add(candidate);
                    break;
            }
        }

        if (expanded.Count == 0)
        {
            expanded.Add(familyName.Trim());
        }

        return expanded.Distinct(StringComparer.OrdinalIgnoreCase).ToArray();
    }

    private static string ResolveIconText(string value, string? familyName, float pointSize)
    {
        if (!TryResolveFontDefinition(familyName, pointSize, out _))
        {
            return NormalizeIconText(value);
        }

        if (TryResolveIconGlyphText(value, familyName, out var glyphText))
        {
            return glyphText;
        }

        return string.Equals(familyName?.Trim(), "lucide", StringComparison.OrdinalIgnoreCase) ? NormalizeIconText(value) : value;
    }

    private static bool TryResolveIconGlyphText(string value, string? familyName, out string glyphText)
    {
        glyphText = string.Empty;

        if (string.IsNullOrWhiteSpace(familyName))
        {
            return false;
        }

        var normalizedFamily = familyName.Trim();
        if (string.Equals(normalizedFamily, "lucide", StringComparison.OrdinalIgnoreCase) && s_lucideGlyphs.TryGetValue(value, out glyphText))
        {
            return true;
        }

        return false;
    }

    private static string NormalizeIconText(string value)
    {
        return value switch
        {
            "sword" => "†",
            "swords" => "⚔",
            "sparkles" => "✦",
            "wand-sparkles" => "✦",
            "shield" => "⛨",
            "flask-conical" => "⚗",
            "flame" => "✹",
            "moon" => "☾",
            "cross" => "✚",
            _ => value
        };
    }

    private static void ApplyIconLabelStyle(Label label, float boxWidth, float boxHeight, float baselineOffset, bool opticalCentering, string sizeMode, float explicitFontSize)
    {
        var iconSize = explicitFontSize > 0f ? explicitFontSize : string.Equals(sizeMode, "match-height", StringComparison.OrdinalIgnoreCase) ? Mathf.Max(1f, boxHeight) : Mathf.Max(1f, Mathf.Min(boxWidth, boxHeight));
        label.style.unityTextAlign = TextAnchor.MiddleCenter;
        label.style.unityFontStyleAndWeight = FontStyle.Normal;
        label.style.whiteSpace = WhiteSpace.NoWrap;
        label.style.flexShrink = 0;
        label.style.alignItems = opticalCentering ? Align.Center : Align.FlexStart;
        label.style.justifyContent = opticalCentering ? Justify.Center : Justify.FlexStart;
        label.style.overflow = Overflow.Visible;
        label.style.paddingLeft = 0f;
        label.style.paddingTop = 0f;
        label.style.paddingRight = 0f;
        label.style.paddingBottom = 0f;
        label.style.width = boxWidth;
        label.style.height = boxHeight;
        label.style.minWidth = boxWidth;
        label.style.minHeight = boxHeight;
        if (opticalCentering && boxWidth >= 32f && boxHeight >= 32f && Mathf.Approximately(baselineOffset, 0f))
        {
            label.style.marginTop = -1f;
        }
        else if (!Mathf.Approximately(baselineOffset, 0f))
        {
            label.style.marginTop = baselineOffset;
        }
        label.style.fontSize = iconSize;
    }
